css:
// ============================================================
// PIETRO EMBALAGENS — CSS Admin (EcomPlus)
// ============================================================

// === OCULTAR FILTROS E ELEMENTOS ===
#c-64ec4f8d2cd6b659592edb20 { display: none !important; }
.checkout__app .recommended-items, .checkout__btn-offers { display: none !important; }
.search-engine__filter--pacote_com,
.search-engine__filter--Categories,
.search-engine__filter--Brands,
.search-engine__filter--forminhas,
.search-engine__filter--composicao_da_caixa,
.search-engine__filter--modelo_da_caixa,
.search-engine__filter--ean { display: none !important; }
#search-bar { display: block !important; }
.payment__badges { display: none; }
.order-info__status--open { display: none; }

// === COMPRE JUNTO ===
.buy-together__item .product-card__buy { display: none !important; }
.buy-together__title {
  position: relative;
  color: #37b8f8;
  font-family: quicksand;
  line-height: 1.22;
  text-decoration: none;
  margin-bottom: 1.25rem;
  > div {
    padding: 0 var(--spacer-3);
    margin: 0 auto;
    display: inline-block;
    background: #fff;
    font-size: 1.375rem;
    font-weight: 700;
    z-index: 2;
    position: relative;
  }
  &::before {
    background: var(--border-color);
    content: " ";
    height: var(--border-width);
    left: 15%;
    margin-top: -.05rem;
    position: absolute;
    top: 50%;
    width: 70%;
  }
}

// === VITRINE DINÂMICA ===
.dynamic-showcase { min-height: 500px; }

// === VÍDEO GALERIA ===
@media screen and (max-width: 480px) {
  .gallery__item--video {
    font-size: 11px;
    margin-top: -13px !important;
    padding: 8px 12px;
    border-radius: 20px;
    background: #fd8043;
    opacity: 1 !important;
    border: none;
    color: #f8f9fa;
  }
}
@media (min-width: 992px) {
  .gallery__item--video {
    padding: var(--spacer-2) 0;
    font-size: 11px !important;
    background: #FF0000;
    border-radius: 5px;
    opacity: 1 !important;
    color: #ffffff;
  }
  .i-play { color: #ffffff !important; }
  .glide__bullets { bottom: 1.75rem; display: none; }
}

// === BLOG ===
.blog-post a { color: #bb8e40; text-decoration: revert; }
blockquote { margin: 0 20px; font-style: italic; }

// === CARRINHO RECOMENDADOS ===
.recommended-items__title { padding-top: 10px; }
.cart__list + .recommended-items .recommended-items__title .lead { font-size: 0; }
.cart__list + .recommended-items .recommended-items__title .lead:after {
  font-size: 25px !important;
  color: #37b8f8 !important;
  content: "Que tal aproveitar o frete?";
}

// === HERO BANNER ===
.hero-banner { margin: 0; }

// === VITRINE INTELIGENTE (CARRINHO) ===
.cart .row .col-md-7 { display: flex; flex-direction: column; }
.cart .row .col-md-7 .cart__list { order: -1; }
.cart .row .col-md-7 .cart__back { order: 2; }
.cart .row .col-md-7 .recommended-items { order: 3; }
.product-card--small .product-card__buy, .product-card .spinner-border {
  bottom: var(--spacer-2);
  right: var(--spacer-4);
}

// === CARROSSEL PRODUTOS ===
.products-carousel h3, .products-carousel strong, .products-carousel .product-card__prices,
.product-card h3, .product-card .product-card__prices, .product-card .prices__discount { text-align: center; }
.products-carousel h3 { color: #705a3d; font-weight: 300; }
.responsive-baner:last-child { padding-bottom: 0 !important; margin-bottom: -1em !important; }

// === DESCONTO / CHECKOUT ===
.discount-applier .alert::after {
  content: '*O valor do desconto não é cumulativo com outras promoções';
}
.cart__summary-row[data-discount^="0.0"],
.summary__amount__row[data-discount^="0.0"] { display: none; }
.summary__item img { width: 50px; }

// === BOTÃO GLOBAL (checkout, etc.) ===
.btn-primary {
  background-color: rgb(40, 167, 69);
  border-color: rgb(40, 167, 69);
  padding: 0.5rem 5rem;
}

// === TABLET ===
@media screen and (min-width: 481px) and (max-width: 997px) {
  .products-carousel .product-card__buy .btn-primary { width: 150px; height: 30px; }
}

// === MOBILE PEQUENO ===
@media screen and (max-width: 480px) {
  .products-carousel .product-card__buy .btn-primary { font-size: 0.7rem; }
  .header__container.container-fluid { margin-top: 0; }
  .top-bar__countdown { font-size: 0.7rem; font-weight: 500; }
  .custom-html + div.responsive-baner { margin-bottom: 2rem !important; }
  #cart-quickview .minicart__aside { margin-top: 1rem; }
}

// === TOPO CONTATOS ===
.top-bar__page-links {
  font-size: .6rem;
  float: right;
  margin-right: -20px;
  text-transform: uppercase;
}

/* ============================================================
   ALPIX — TEMA PRINCIPAL
   ============================================================ */

@import url('https://fonts.googleapis.com/css2?family=PT+Sans:wght@400;700&display=swap');

@font-face {
  font-family: quicksand;
  src: url(/assets/fonts/quicksand-Regular-w2.woff2) format("woff2"), url(/assets/fonts/quicksand-Regular-w.woff) format("woff");
  font-weight: 400;
  font-style: normal;
  font-display: swap;
}
@font-face {
  font-family: quicksand;
  src: url(/assets/fonts/quicksand-Semibold-w2.woff2) format("woff2"), url(/assets/fonts/quicksand-Semibold-w.woff) format("woff");
  font-weight: 600;
  font-style: normal;
  font-display: swap;
}
@font-face {
  font-family: quicksand;
  src: url(/assets/fonts/quicksand-Bold-w2.woff2) format("woff2"), url(/assets/fonts/quicksand-Bold-w.woff) format("woff");
  font-weight: 700;
  font-style: normal;
  font-display: swap;
}

:root {
  --apx_azul: #4698ca;
  --apx_azul2: #37b8f8;
  --apx_laranja1: #FFBF3F;
  --apx_laranja2: #FF5E0F;
  --apx_laranja2_h: #fd8043;
  --apx_cinza: #6A6A57;
  --apx_marrom: #76574b;
}

body #header .top-bar,
body #header .top-bar__nav { background: #fff; }

article#content, main { background: #fff; }

.h1, .h2, .h3, .h4, .h5, .h6, h1, h2, h3, h4, h5, h6 {
  margin-bottom: 0;
  font-family: quicksand;
  font-weight: 700;
  line-height: 1.22;
  font-size: 18px;
}

body {
  font-family: "Quicksand", sans-serif;
  font-size: 1rem;
  font-weight: 400;
  line-height: 1.68;
  color: #6A6A57;
}

.top-bar a.top-bar__countdown { padding: 0.3rem 0; font-size: 15px; }
.top-bar__page-links a {
  color: var(--apx_cinza);
  font-size: 12px;
  text-transform: initial;
  font-weight: normal;
}

#search-input {
  border: 1px dashed #4698ca !important;
  border-radius: 10px;
  text-transform: initial !important;
  font-family: quicksand;
  font-size: 12px !important;
  background: #ffffff;
}

.header__search-btn .fa-search,
.header__buttons .btn { color: var(--apx_azul); }
.header__container { margin: 0 auto; padding: 15px; }
.badge-primary { background: var(--apx_laranja2_h); }

.header__nav {
  display: flex;
  justify-content: space-between;
  max-width: 1080px;
  margin: 0 auto;
}
.header__row .header__nav a {
  color: #4698ca;
  position: relative;
  font-weight: 700 !important;
  padding: 18px 0;
  font-size: 18px;
  margin: 0;
}
.header__row .header__nav a:hover { background: transparent; }
.header__row .header__nav a:hover:after { opacity: 1; }
.header__row .header__nav a:after {
  background: var(--apx_azul2);
  position: absolute;
  content: "";
  bottom: 0;
  left: 0;
  width: 100%;
  height: 3px;
  opacity: 0;
  transition: .2s cubic-bezier(.4, 0, .22, 1);
}

#header {
  background-color: #ffffff !important;
  box-shadow: 0 .5rem 1rem rgba(0,0,0,.15) !important;
  border-width: 0;
  padding: 0;
}
.header__row { padding-left: 15px; padding-right: 15px; }
#header .d-lg-block.order-lg-last {
  margin: 15px 0 -23px 0;
  background: #fff;
  width: 100vw;
  max-width: unset;
  flex: 0 0 100vw;
  position: relative;
  transform: translate(-50%, 0);
  left: 50%;
}

.products-carousel { background: transparent; }

.product-card > .product-card {
  border: 0;
  box-shadow: unset;
  padding: 15px 15px 30px;
  margin-bottom: 30px;
  border-radius: 0;
  background: #fff;
}

.product-card .product-card__buy {
  position: absolute;
  width: auto;
  height: auto;
  display: grid;
  place-content: center;
  opacity: 0 !important;
  z-index: 10;
  transition: opacity .5s;
  transform: translate(-50%, -50%);
  top: 50%;
  left: 50%;
}
.product-card:hover .product-card__buy { opacity: 1 !important; visibility: visible; }

.product-card__buy .fas { display: none; }
.product-card__buy .btn-primary {
  background: var(--apx_laranja2);
  color: #fff;
  font-weight: 700;
  font-size: 14px;
  letter-spacing: .15em;
  border: none;
  font-family: quicksand;
  text-transform: uppercase;
  line-height: 47px;
  height: auto;
  border-radius: 47px;
  padding: 0 25px;
  min-width: 180px;
  transition: .2s opacity;
}

.products-carousel__title { margin: 1rem 0; text-transform: uppercase; color: #37b8f8; font-weight: 700; }
.products-carousel__title a, .products-carousel__title span {
  font-size: 2rem;
  color: #37b8f8;
  font-family: quicksand;
  font-weight: 700;
  line-height: 1.22;
  text-decoration: none;
}
.products-carousel__title a::after {
  background: #fff;
  content: ' + Ver mais';
  font-size: 0.90rem;
  font-weight: bold;
  padding: 0.5rem;
  color: #37b8f8 !important;
}

.product-card__name {
  font-size: 1rem;
  color: #76574b;
  font-family: quicksand;
  font-weight: 700 !important;
  line-height: 1.22rem;
  height: auto;
  margin-bottom: 5px;
}

.prices__value {
  font-size: 1.7rem;
  color: #4698ca;
  font-family: quicksand;
  font-weight: 700;
  line-height: 1.22;
}

.glide__arrows--outer .glide__arrow--left,
.glide__arrows--outer .glide__arrow--right {
  background-color: var(--apx_laranja2);
  color: #fff;
  font-size: 14px;
  height: 50px;
  width: 50px;
  border-radius: 50%;
  opacity: 1;
}
.glide__arrows--outer .glide__arrow--left { left: -25px; }
.glide__arrows--outer .glide__arrow--right { right: -25px; }

h1 {
  font-size: 2rem !important;
  font-family: quicksand;
  font-weight: 700;
  line-height: 1.22;
  color: var(--apx_marrom);
}

#product-description .lead {
  font-size: 1.6875rem;
  color: #FD8043;
  margin-bottom: 0;
  font-family: quicksand;
  font-weight: 700;
  line-height: 1.22;
}
#product-description .html-clearfix { padding: 30px; margin-bottom: 30px; background: #fff; }

.stamps { display: flex; flex-wrap: wrap; }
.stamps > li { justify-content: space-between; }
.stamps > li img { max-height: 75px; }

@media (min-width: 990px) {
  #content > div > .banner-slider:first-child {
    max-width: 100%;
    --banner-aspect-ratio: 1 !important;
    --banner-aspect-ratio-mobile: 1;
    height: auto;
  }
}
@media (max-width: 990px) {
  .products-carousel__title a, .products-carousel__title span { font-size: 1.3rem; }
}

// === BUSCA INSTANTÂNEA ===
.header__search { overflow: visible; }
#header #instant-search .search__box.card {
  position: absolute;
  left: 0;
  top: 100%;
  margin: 0;
  z-index: 1080;
  box-shadow: 5px 5px 5px rgba(0,0,0,.1);
  border-radius: 0;
  width: 550px;
  border-top: 4px solid var(--apx_azul);
  margin-top: 15px;
}
#header .search__history .fas,
#header .search__count { color: #fff; }
#header .search__history { text-align: right; }
#header .search__body { max-height: 50vh; }
#header #instant-search .search__box.card .search__header { display: flex; }
#header #instant-search .search__box.card .search-engine__results .search-engine__info h3 { display: none; }
#header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row { display: block; }
#header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row > div {
  display: block; width: 100%; max-width: 100%;
}
#header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row > div .product-card .product-card__buy,
#header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row > div .product-card .product-card__offer-stamp { display: none; }
#header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row > div .product-card section,
#header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row > div .product-card section .product-card__link { display: flex; align-items: center; }
#header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row > div .product-card section .product-card__pictures { height: auto; }
#header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row > div .product-card section picture { max-width: 100px; height: 100%; }
#header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row > div .product-card .product-card__name {
  padding: 0 1rem; white-space: normal; width: 350px; text-align: left; font-size: 12px;
}
#header #instant-search .search__box.card .search-engine .lead { font-size: 14px; margin-top: .5rem; }
#header #instant-search .search__box.card .search-engine h4 { font-size: 18px; }
#header #instant-search .search__box.card .search-engine__results .prices { text-align: right; align-items: center; display: flex; }
#header #instant-search .search__box.card .search-engine__results .prices > * { margin: 0; display: block; text-align: right; font-size: 18px; }
#header #instant-search .product-card { box-shadow: unset !important; }
.search__footer { font-size: 12px; background: var(--apx_azul); border-radius: 0; border: 0; }
.search__history, .search__history a, .search__count { color: #fff; font-size: 12px; white-space: normal; }

@media (min-width: 992px) {
  #header #instant-search .search__box.card { left: -30% !important; }
}
@media (max-width: 990px) {
  #header #instant-search .search__box.card {
    position: fixed !important;
    top: 70px; left: 8px; right: 8px;
    width: auto !important;
    max-width: calc(100% - 16px) !important;
    max-height: 65vh;
    overflow-y: auto;
    margin-top: 0 !important;
  }
  #header #instant-search .search__box.card .product-card__pictures { display: none; }
  #header #instant-search .search__box.card .search-engine__results .search-engine__retail > .row > div .product-card .product-card__name { padding-left: 0; width: 100%; font-size: .7rem; }
  #header #instant-search .search-engine__item { padding: 0; }
  #header #instant-search .search-engine__info { padding-bottom: 0; }
  #header #instant-search .product-card__prices .prices__compare { font-size: .8rem; }
  #header #instant-search .product-card__prices .prices__value { font-size: .8rem; }
  #header #instant-search .search__body { min-height: unset; max-height: 45vh !important; }
  #header #instant-search .search__box.card .search-engine__results .prices > * { font-size: 14px; }
  .search__box.card .search-engine__results .search-engine__retail > .row > div .product-card section { justify-content: space-between; }
  .products-carousel h3 { font-size: 14px; }
  .glide__arrows--outer .glide__arrow--right { right: 0; }
  .glide__arrows--outer .glide__arrow--left { left: 0; }
  .glide__arrows--outer .glide__arrow--left, .glide__arrows--outer .glide__arrow--right { height: 25px; width: 25px; padding: 0; }
  #checkout .product-card .product-card__buy > button:after { line-height: normal !important; }
}

// === FOOTER ===
.footer { background: #37b8f8; color: #fff; padding-top: 0; border: 0; }
.footer__title + p { color: #fff !important; }
.footer a,
.footer__title + ul.list-unstyled > li:nth-child(2) > a,
.footer__title + ul.list-unstyled > li:first-child a,
.footer__title + ul.list-unstyled > li:first-child span,
.footer__list-icon { color: #fff !important; }
.footer .col-lg-auto { width: 20%; }
.footer__credits { border-top: 1px solid #000; text-align: center; }
.footer__credits, .footer__credits * { color: #fff; font-family: quicksand; border-color: #002053; }
.footer * { font-size: 16px; letter-spacing: .028em; font-family: quicksand; }
.footer .footer__title {
  color: #76574b !important;
  font-family: quicksand;
  font-weight: 800;
  font-size: 18px;
  text-transform: uppercase;
  letter-spacing: .15em;
}
.footer__links svg { display: none !important; }
.footer__links li > i { display: none; }
.footer__links li { margin-bottom: 5px; }
.pay-icon { background-color: #fff; }
.stamps > li {
  background: #fff;
  border-radius: 3px;
  text-align: center;
  align-items: center;
  padding: 10px;
  flex: 0 0 31%;
  justify-content: space-between;
  margin: 0 10px 10px 0 !important;
}
.stamps > li img { max-height: 60px !important; width: auto; }
.footer__social a, .footer__social a i { font-size: 18px; }
.footer__stamps li:nth-child(3) > img { width: auto; }

// === MENU ===
.menu__list a.menu__item > span { background: transparent !important; }
.menu__list a.menu__item:hover > span { color: #fff !important; background: transparent !important; }
.menu__list a.menu__item:hover { background: var(--apx_azul) !important; transition: all .2s; }
#menu .menu__list span, .header__toggler span, .menu__item span {
  color: var(--apx_azul);
  position: relative;
  font-weight: 700 !important;
  padding: 16px 0;
  text-transform: uppercase;
  font-size: 16px;
  margin: 0;
  font-family: "Montserrat", sans-serif;
}
.menu__item { border: 0; padding: 0 15px; }
#accordion-menu .menu__item span.menu__item-icon { padding: 0; height: auto !important; }
#accordion-menu > div:not(#categories-nav) .menu__list .menu__item-icon img { padding: 10px; }
#accordion-menu > div:not(#categories-nav) .menu__list a:hover .menu__item-icon img { filter: brightness(100); }
#menu .menu__btn--close, .menu__btn.btn.collapsed { color: #000 !important; }
.menu__item-icon > img { max-width: 240% !important; max-height: 200% !important; }
.menu__item-icon { margin-right: 3.1rem !important; height: 3.45rem !important; }
.menu__phone { display: flex !important; flex-direction: column; }

// === TOP BAR ===
.top-bar__nav, .top-bar { background: #fff; }
.top-bar__nav { display: none !important; }

// === MINICART ===
.minicart__btn-checkout.btn, .cart__info .cart__btn-checkout { font-size: 0; }
.minicart__btn-checkout.btn::after, .minicart__btn-checkout.btn svg,
.cart__info .cart__btn-checkout::after, .cart__info .cart__btn-checkout svg {
  font-size: 1rem !important;
  content: 'Finalizar compra';
  margin-left: .2rem;
}

// === CART ===
#cart .product-card__buy .btn-primary {
  font-size: 12px; height: auto; line-height: 18px;
  padding: 5px 16px; width: auto; min-width: auto;
  margin: 0 auto; display: block; letter-spacing: 1px;
}
#cart .product-card { box-shadow: none; }
#cart .product-card .prices__value { font-size: 1.2rem; }

// === PRODUCT CARD (estado final com qtde) ===
.product-card:hover { box-shadow: unset; }
.product-card .product-card__buy {
  opacity: 1 !important;
  position: relative;
  top: auto; bottom: auto; left: auto;
  margin: 0;
  transform: unset;
  background: transparent !important;
  display: flex;
  align-items: center;
  gap: 15px;
}
.product-card__buy { margin-top: 1rem !important; }
.product-card__buy .btn-primary { padding: 0; width: fit-content; min-width: unset; line-height: 36px; }
.product-card__buy .btn-primary div { padding: 0 15px; }
.page--search .search-engine__results > .container { padding: 0; }

@media (max-width: 990px) {
  .product-card .product-card__buy,
  .product-card:hover .product-card__buy,
  .recommended-items .product-card__buy {
    position: relative !important;
    top: auto;
    margin: 15px 0 0 0;
    opacity: 1 !important;
  }
  .product-card__buy .btn-primary { font-size: 10px; height: auto; line-height: initial; padding: 8px 18px; width: auto; min-width: unset; }
  .product-card__name { font-size: 14px; overflow: hidden; }
  .prices__value { font-size: 1.4rem; }
  #product-description .lead, h1 { font-size: calc(var(--h1) * 0.6) !important; }
  .prices--big .prices__value { font-size: calc(var(--h1) * 0.8); }
  .stamps > li { flex: 0 0 calc(50% - 10px); width: auto; min-width: auto; }
  .product-card .product-card__buy { flex-direction: column; }
  .product-card .product-card__buy > * { width: 100% !important; justify-content: space-between; }
  .app__stamps > .stamps { justify-content: center; }
  .recommended-items .product-card__buy { position: relative !important; }
  #search-bar form > button:first-child { padding: 0 10px; line-height: initial; }
}
@media (min-width: 990px) {
  .app__footer .stamps > li { flex: 0 0 auto; }
  .app__stamps > .stamps { justify-content: center; }
}

// === RECOMMENDED ITEMS ===
.recommended-items .product-card__buy {
  display: flex !important;
  position: relative !important;
  flex-direction: column !important;
  transform: unset;
  width: auto;
  left: auto;
  right: auto;
}
.recommended-items .product-card__buy .btn-primary div { padding: 0; }

// === CHECKOUT ===
#checkout .product-card .product-card__buy > button { min-width: 70%; margin: 0 auto; font-size: 0; line-height: 0; }
#checkout .product-card .product-card__buy > button:after { font-size: 14px; content: "Adicionar"; display: block; line-height: 47px; }
.stamps > li #seloEconfy > img { max-width: unset !important; width: unset !important; }

// === ESTILOS SLIDER ===
#estilos-slider { align-items: center; margin-top: -1.5rem; margin-bottom: -1.5rem; }
#estilos-slider > div > strong { color: #606395; font-size: 1.2rem; line-height: 1.2rem; }
#estilos-slider .glide__slide strong { display: block; font-size: 15px; font-weight: normal; margin-top: 5px; color: #705a3d; }
#estilos-slider .glide__slide a { display: block; text-align: center; }
#accordion-menu > div:not(#categories-nav) .menu__list .menu__item-icon img { padding: 10px; }
#accordion-menu > div:not(#categories-nav) .menu__list a:hover .menu__item-icon img { filter: brightness(100); }
@media (max-width: 990px) {
  #estilos-slider > div > strong { color: #606395; text-align: center; margin: 30px 0; width: 100%; display: block; }
  #estilos-slider { padding: 0 1.5em; }
  #estilos-slider .btn.glide__arrow--left { left: -2em; }
  #estilos-slider .btn.glide__arrow--right { right: -2em; }
  footer #seloEconfy img { max-width: auto !important; width: unset !important; }
}
.app .stamps img { opacity: 1 !important; }

// === QUANTITY SELECTOR (APX) ===
.product__buy .apx_quantity_selector { position: relative; }
.product__buy .apx_quantity_selector button:last-child { left: auto; right: 0; }
.product__buy .apx_quantity_selector button i { font-size: 12px; line-height: 32px; }
.product__buy .apx_quantity_selector button {
  background: transparent; border: 0; border-radius: 7px; color: #333;
  height: 34px; left: 0; margin: 7px; position: absolute;
  text-align: center; top: 0; width: 34px; z-index: 2;
}
.product__buy .apx_quantity_selector input {
  background: #f7f7f7; border: 0; border-radius: 5px; font-size: 18px;
  height: 48px; letter-spacing: 1px; pointer-events: none;
  text-align: center; width: 120px; font-weight: bold;
}
@media (max-width: 990px) {
  .product__buy .apx_quantity_selector + span { width: 100%; }
  .product__buy .apx_quantity_selector + span .btn-primary { white-space: nowrap; padding-left: 0; padding-right: 0; width: 100%; }
  .product__buy .apx_quantity_selector input { width: 130px; }
}

// === SHARES / PAGAMENTO ===
.share-network-facebook, .share-network-whatsapp, .share-network-twitter,
.share-network-telegram, .share-network-pinterest, .share-network-email,
.share-network-sms, .product__payment.card { display: none; }

// === QTDE ADICIONAR CARRINHO ===
.qtde-adicionar-carrinho {
  margin: 0; display: flex; align-items: center; text-align: center;
  border: 1px solid #f4f4f4; line-height: 36px; border-radius: 36px; width: auto; padding: 0 10px;
}
.qtde-adicionar-carrinho > input { -moz-appearance: textfield; height: 36px; padding: 0; width: 40px; border: 0; text-align: center; }
.qtde-adicionar-carrinho > input::-webkit-outer-spin-button,
.qtde-adicionar-carrinho > input::-webkit-inner-spin-button { -webkit-appearance: none; margin: 0; }
input[type=number] { -moz-appearance: textfield; }
.qtde-adicionar-carrinho > button { border: 0; padding: 0; background: transparent; }
.qtde-adicionar-carrinho > button > svg { height: 16px; margin: 0; display: block; width: 16px; }

// === MINHA CONTA ===
#user-button:after { content: "Minha Conta"; font-size: 11px; position: absolute; top: 39px; left: -13px; width: 60px; }

// === INFO BAR / MISC ===
.info-bar { background: #37b8f8; color: #ffffff; width: 100%; }
.info-bar__title { font-weight: bold; }
.info-bar__text { text-transform: initial; font-size: 16px; }
.rounded-icon { border: 1px solid #4698ca; }
.collection-shelf { margin-top: 1rem; }

// === DIREITA ===
.direita, .direita1, .direita2 { display: none; }
@media (min-width: 767px) {
  .direita { position: absolute; top: 8.5px; right: .8%; text-transform: uppercase; display: block !important; }
  .direita1 { position: absolute; top: 8.5px; right: 34%; text-transform: uppercase; display: block !important; }
  .direita2 { position: absolute; top: 8.5px; right: 68%; text-transform: uppercase; display: block !important; }
  #clube, #cnpj { display: none; }
}

// === PAGAMENTO 123188 ===
.payment__gateway--123188:last-child { border-bottom: 2px solid #002053; }
.payment__gateway--123188 {
  border-left: 2px solid #002053;
  border-right: 2px solid #002053;
  background-color: #2d507a;
  color: #fff;
  .payment__back i { color: #fff; }
}

@media (max-width: 767px) {
  #apx_menu a > svg.ionicon { display: none !important; }
}

// === QUANTITY SELECTOR (componente padrão) ===
.quantity-selector__btn-container {
  input { background: #f7f7f7; border: none; height: 49px; border-radius: 0; }
  .btn {
    background: #f7f7f7;
    &:first-of-type { border-top-right-radius: 0; border-bottom-right-radius: 0; }
    &:last-of-type { border-top-left-radius: 0; border-bottom-left-radius: 0; }
  }
}

// === SOBRE NÓS ===
.sobre_cell_title h4 {
  margin-bottom: 20px;
  font: normal normal 400 30px/40px quicksand;
  letter-spacing: 0;
  color: #37b8f8;
  &::after { content: ""; background: #eee; height: 1px; width: 100%; display: block; }
  span { border-bottom: 2px solid #37b8f8; }
}
.sobre_cell_text {
  display: flex;
  flex-direction: column;
  h5 { font: normal normal bold 20px/40px quicksand; letter-spacing: 0; color: #333333; margin: 20px 0; }
  p { font: normal normal 300 18px/36px quicksand; letter-spacing: 0; color: #333333; margin-bottom: 30px; }
  a { background: #4698ca; border-radius: 50px; font: normal normal bold 18px/40px quicksand; letter-spacing: 0; color: #FFFFFF; text-transform: uppercase; padding: 5px 110px; width: 60%; }
}
.sobre_cell_video {
  .celltronics-mobileonly { display: none; background: #4698ca; border-radius: 50px; font: normal normal bold 18px/40px quicksand; letter-spacing: 0; color: #FFFFFF; text-transform: uppercase; padding: 5px 110px; }
  iframe { width: 100%; height: 485px; }
}
@media (max-width: 767px) {
  .custom-html.my-4.my-lg-5:last-child .html-clearfix { overflow: hidden; }
  .sobre_cell_text p, .celltronics-deskonly { display: none !important; }
  .sobre_cell_text { flex-direction: column; }
  .celltronics-mobileonly { display: flex !important; margin-top: 7%; }
  .sobre_cell_video { width: 100%; iframe { width: 100%; height: auto; } }
  .sobre_cell_container { text-align: center; }
}
